# Primitive types and interfaces
from config import Color, PI

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

interface IShape:
    def area(self) -> float:
        ...

    def perimeter(self) -> float:
        ...

    def get_category(self) -> str:
        ...

class ShapeBase:
    color: Color
    position: Point

    def __init__(self, color: Color, position: Point):
        self.color = color
        self.position = position

    @virtual
    def describe(self) -> str:
        return "Base shape"

    @virtual
    def area(self) -> float:
        return 0.0

    @abstract
    def perimeter(self) -> float:
        ...

    def get_position_str(self) -> str:
        return f"({self.position.x}, {self.position.y})"

