# Concrete shape implementations
from config import Color, PI, get_color_name
from primitives import Point, ShapeBase, IShape

class Circle(ShapeBase, IShape):
    radius: float

    def __init__(self, radius: float, color: Color, position: Point):
        super().__init__(color, position)
        self.radius = radius

    @override
    def area(self) -> float:
        return PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * PI * self.radius

    @override
    def describe(self) -> str:
        return f"Circle(r={self.radius})"

    def get_category(self) -> str:
        return "Round"

class Rectangle(ShapeBase, IShape):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color, position: Point):
        super().__init__(color, position)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return f"Rectangle({self.width}x{self.height})"

    def get_category(self) -> str:
        return "Rectangular"

    def is_square(self) -> bool:
        return self.width == self.height

def calculate_total_area(shapes: list[ShapeBase]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.area()
    return total
